# Category: information_disclosure

import android.util.Log
import okhttp3.logging.HttpLoggingInterceptor
import timber.log.Timber
import java.io.PrintWriter
import java.io.StringWriter
import java.util.concurrent.ConcurrentHashMap

class ComprehensiveLogger {
    companion object {
        private const val TAG = "ComprehensiveLogger"
        private val loggedAuthAttempts = ConcurrentHashMap<String, Long>()
        private val loggedDatabaseQueries = ConcurrentHashMap<String, Long>()
        private val loggedApiRequests = ConcurrentHashMap<String, Long>()
        
        fun logUserAuthenticationAttempt(
            userId: String,
            isSuccess: Boolean,
            errorMessage: String? = null
        ) {
            val logMessage = buildString {
                append("Auth Attempt - User: $userId, Success: $isSuccess")
                if (errorMessage != null) {
                    append(", Error: $errorMessage")
                }
            }
            
            if (isSuccess) {
                Timber.tag(TAG).v(logMessage)
            } else {
                Timber.tag(TAG).w(logMessage)
            }
            
            // Track recent attempts
            loggedAuthAttempts[userId] = System.currentTimeMillis()
        }
        
        fun logDatabaseQuery(
            query: String,
            parameters: Map<String, Any?>,
            executionTimeMs: Long,
            isError: Boolean = false
        ) {
            val logMessage = buildString {
                append("DB Query - Time: ${executionTimeMs}ms")
                append(", Query: $query")
                if (parameters.isNotEmpty()) {
                    append(", Params: $parameters")
                }
                if (isError) {
                    append(", Error occurred")
                }
            }
            
            if (isError) {
                Timber.tag(TAG).e(logMessage)
            } else {
                Timber.tag(TAG).v(logMessage)
            }
            
            // Track recent queries
            loggedDatabaseQueries[query] = System.currentTimeMillis()
        }
        
        fun logApiRequest(
            url: String,
            method: String,
            headers: Map<String, String>,
            requestBody: String?,
            responseCode: Int,
            responseBody: String?,
            executionTimeMs: Long,
            isError: Boolean = false
        ) {
            val logMessage = buildString {
                append("API Request - $method $url")
                append(", Time: ${executionTimeMs}ms")
                append(", Response: $responseCode")
                append(", Headers: $headers")
                if (requestBody != null) {
                    append(", Request Body: $requestBody")
                }
                if (responseBody != null) {
                    append(", Response Body: $responseBody")
                }
                if (isError) {
                    append(", Error occurred")
                }
            }
            
            if (isError) {
                Timber.tag(TAG).e(logMessage)
            } else {
                Timber.tag(TAG).v(logMessage)
            }
            
            // Track recent requests
            loggedApiRequests[url] = System.currentTimeMillis()
        }
        
        fun logException(
            exception: Throwable,
            context: String = "Unknown"
        ) {
            val stackTrace = StringWriter()
            exception.printStackTrace(PrintWriter(stackTrace))
            
            val logMessage = buildString {
                append("EXCEPTION - Context: $context")
                append(", Class: ${exception.javaClass.name}")
                append(", Message: ${exception.message}")
                append(", StackTrace: ${stackTrace.toString()}")
            }
            
            Timber.tag(TAG).e(logMessage)
        }
        
        fun logVerbose(message: String) {
            Timber.tag(TAG).v(message)
        }
        
        fun logDebug(message: String) {
            Timber.tag(TAG).d(message)
        }
        
        fun logInfo(message: String) {
            Timber.tag(TAG).i(message)
        }
        
        fun logWarning(message: String) {
            Timber.tag(TAG).w(message)
        }
        
        fun logError(message: String) {
            Timber.tag(TAG).e(message)
        }
        
        fun getRecentLogs(): Map<String, Any> {
            return mapOf(
                "auth_attempts" to loggedAuthAttempts,
                "database_queries" to loggedDatabaseQueries,
                "api_requests" to loggedApiRequests
            )
        }
    }
}

class ProductionTimberTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        when (priority) {
            Log.VERBOSE -> Log.v(tag, message)
            Log.DEBUG -> Log.d(tag, message)
            Log.INFO -> Log.i(tag, message)
            Log.WARN -> Log.w(tag, message)
            Log.ERROR -> Log.e(tag, message)
        }
        
        if (t != null) {
            Log.e(tag, "Exception occurred", t)
        }
    }
}

class HttpLoggingInterceptorWrapper {
    private val interceptor = HttpLoggingInterceptor { message ->
        ComprehensiveLogger.logVerbose("HTTP_LOG: $message")
    }
    
    fun getInterceptor(): HttpLoggingInterceptor {
        interceptor.level = HttpLoggingInterceptor.Level.BODY
        return interceptor
    }
}

class LoggerSetup {
    companion object {
        fun initialize() {
            if (Timber.tag("ComprehensiveLogger") == null) {
                Timber.plant(ProductionTimberTree())
            }
        }
    }
}

